import{_ as e,c as o,o as s,ag as n}from"./chunks/framework.DVUBUV_u.js";const u=JSON.parse('{"title":"Auto run","description":"","frontmatter":{"title":"Auto run"},"headers":[],"relativePath":"options/auto_run.md","filePath":"options/auto_run.md"}'),r={name:"options/auto_run.md"};function i(a,t,l,h,g,c){return s(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="auto-run" tabindex="-1">Auto run <a class="header-anchor" href="#auto-run" aria-label="Permalink to &quot;Auto run&quot;">​</a></h1><blockquote><p><strong>Extension only (Chrome / Edge).</strong> The <strong>Auto Run</strong> block in <strong>Options → General</strong> is <strong>hidden</strong> in <strong>standalone</strong>: a bookmark has no background extension process to decide when to show the panel.</p></blockquote><p><strong>Auto Run</strong> controls <strong>when</strong> the overlay <strong>pill</strong> appears on sites in <strong>overlay</strong> mode. This is <strong>not</strong> the component <strong>blacklist</strong> on <strong>Props</strong> — here we only filter <strong>site origins</strong> (scheme, host, port).</p><hr><h2 id="basics" tabindex="-1">Basics <a class="header-anchor" href="#basics" aria-label="Permalink to &quot;Basics&quot;">​</a></h2><p>Rules inspect the page <strong>origin</strong> (address bar host, no path). You can enter a full URL such as <code>https://app.example/</code> or a pattern like <code>*localhost*</code> where <code>*</code> matches any substring. Empty lists impose no restriction until you add rows (or enable whitelist mode, below).</p><p>The overlay still <strong>won’t</strong> inject on pages the extension treats as <strong>static without Vue</strong> (separate heuristic). Lists don’t bypass that — see the extension <strong>popup</strong> section.</p><hr><h2 id="site-blacklist" tabindex="-1">Site Blacklist <a class="header-anchor" href="#site-blacklist" aria-label="Permalink to &quot;Site Blacklist&quot;">​</a></h2><p><strong>Site Blacklist</strong> — origins/patterns where the pill <strong>must not</strong> auto-show.</p><ul><li>Add via input + <strong>Add</strong> (or Enter).</li><li>Table shows <strong>pattern</strong> and <strong>added</strong> date; select a row to edit in the side panel.</li><li>If the current origin <strong>matches any</strong> blacklist row, auto-run overlay is off for that tab.</li></ul><p>Blacklist can combine with whitelist: whitelist is evaluated first when active and non-empty.</p><hr><h2 id="site-whitelist-and-whitelist-mode" tabindex="-1">Site Whitelist and “whitelist mode” <a class="header-anchor" href="#site-whitelist-and-whitelist-mode" aria-label="Permalink to &quot;Site Whitelist and “whitelist mode”&quot;">​</a></h2><p><strong>Enable whitelist mode</strong> activates <strong>Site Whitelist</strong>.</p><ul><li>While the whitelist is <strong>empty</strong>, mode is effectively open — only blacklist (if any) applies.</li><li>Once the whitelist has <strong>at least one</strong> row, auto overlay is <strong>only</strong> allowed on matching origins; everything else is denied <strong>before</strong> blacklist trims further.</li></ul><p>So a <strong>non-empty whitelist</strong> defines “where yes”, <strong>blacklist</strong> subtracts exceptions.</p><hr><h2 id="extension-popup-—-escape-hatch" tabindex="-1">Extension popup — escape hatch <a class="header-anchor" href="#extension-popup-—-escape-hatch" aria-label="Permalink to &quot;Extension popup — escape hatch&quot;">​</a></h2><p>The extension icon <strong>popup</strong> exposes two actions (UI labels in English: <strong>Forced Launch</strong>, <strong>Reset Settings</strong>).</p><p><strong>Forced Launch</strong> injects the inspector on the <strong>active tab</strong>, <strong>ignoring</strong> Auto Run lists and the static-site heuristic. Use when lists block all sites or <strong>Options</strong> is unreachable.</p><p><strong>Reset Settings</strong> performs a <strong>full wipe</strong> of saved inspector settings (Auto Run, theming, favorites, etc.). Last resort if configuration locks you out — there is <strong>no</strong> undo without a backup export.</p><p>If you rely on a strict whitelist, keep at least one URL you use to open <strong>Options</strong>, or remember <strong>Forced Launch</strong> / <strong>Reset Settings</strong>.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/install.html#storage">Installation → Where settings are stored</a></li><li><a href="/docs/extension.html">Browser extension</a></li></ul>',26)])])}const d=e(r,[["render",i]]);export{u as __pageData,d as default};
